let state = flow.get("device_state") || "unknown";

if (state !== "offline") {
    flow.set("device_state", "offline");

    msg.payload = "🚨 OFFLINE - Test enhet";
    msg.headers = {
        "Content-Type": "text/plain"
    };
    return msg;
}

return null;

let state = flow.get("device_state") || "unknown";

if (state !== "online") {
    flow.set("device_state", "online");

    msg.payload = "✅ ONLINE - Test enhet";
    msg.headers = {
        "Content-Type": "text/plain"
    };
    return msg;
}

return null;

let allowedDevices = [
    "plc-001",
    "plc-002"
];

// 🔥 Viktigste linje – støtter begge input-typer
let deviceId = msg.deviceId || msg.payload?.device_id;

if (!deviceId) {
    node.warn("Mangler deviceId (hverken msg.deviceId eller payload.device_id)");
    return null;
}

if (!allowedDevices.includes(deviceId)) {
    node.warn("Ukjent device forsøkte tilgang: " + deviceId);
    return null;
}

let devices = flow.get("devices", "default") || {};
let now = Date.now();
let nowStr = new Date().toLocaleString();

if (!devices[deviceId]) {
    devices[deviceId] = {
        state: "unknown",
        last_seen: 0,
        missed_count: 0
    };
}

// Oppdater heartbeat
devices[deviceId].last_seen = now;
devices[deviceId].missed_count = 0;

// Send ONLINE kun ved endring
if (devices[deviceId].state !== "online") {
    devices[deviceId].state = "online";
    flow.set("devices", devices, "default");

    msg.payload = `🟢 ENHET ONLINE
Enhet: ${deviceId}
Tid: ${nowStr}`;

    msg.headers = {
        "Content-Type": "text/plain"
    };

    return msg;
}

flow.set("devices", devices, "default");
return null;

node.warn("CHECK RUNNING");

let devices = flow.get("devices", "default") || {};
let timeout = 15000;
let now = Date.now();
let nowStr = new Date().toLocaleString();

for (let deviceId in devices) {

    let lastSeen = devices[deviceId].last_seen || 0;
    let state = devices[deviceId].state || "unknown";
    let missed = devices[deviceId].missed_count || 0;

    if ((now - lastSeen) > timeout) {

        devices[deviceId].missed_count = missed + 1;

        if (devices[deviceId].missed_count === 1) {
            devices[deviceId].state = "suspect";
            flow.set("devices", devices, "default");
            return null;
        }

        if (devices[deviceId].missed_count >= 2 && state !== "offline") {
            devices[deviceId].state = "offline";
            flow.set("devices", devices, "default");

            msg.payload = `🔴 ENHET OFFLINE
Enhet: ${deviceId}
Tid: ${nowStr}`;

            msg.headers = {
                "Content-Type": "text/plain"
            };

            return msg;
        }
    }
}

flow.set("devices", devices, "default");
return null;

if (msg.payload === true || msg.payload === false) {
    return msg;
}
return null;

if (msg.payload !== true) {
    return null;
}

msg.headers = {
    "Title": "Opta alarm",
    "Priority": "high",
    "Tags": "warning,rotating_light"
};

msg.payload = "DI1 aktiv på opta-1";

return msg;

let resendMs = 24 * 60 * 60 * 1000;   // 24 timer
let resetMs  = 10 * 60 * 1000;        // 10 minutter uten alarm
let now = Date.now();

let lastSent = flow.get("di1_last_sent") || 0;
let falseSince = flow.get("di1_false_since") || 0;

// Alarm aktiv
if (msg.payload === true) {
    // alarmen er tilbake, så vi nuller false-timer
    flow.set("di1_false_since", 0);

    if ((now - lastSent) >= resendMs) {
        flow.set("di1_last_sent", now);
        return msg;
    }

    return null;
}

// Alarm ikke aktiv
if (msg.payload === false) {
    if (falseSince === 0) {
        flow.set("di1_false_since", now);
        return null;
    }

    // hvis signalet har vært borte lenge nok, nullstill resend-timeren
    if ((now - falseSince) >= resetMs) {
        flow.set("di1_last_sent", 0);
    }

    return null;
}

return null;
